const payload = $input.first().json.body ?? $input.first().json;
const customer = payload.customer ?? {};
const request = payload.request ?? {};
const tags = [
  'OBMC AI Employees',
  'Setup Request',
  customer.plan_id ? `Plan: ${customer.plan_id}` : null,
  request.currentGhl ? `GHL: ${request.currentGhl}` : null
].filter(Boolean);

return [{
  json: {
    event: payload.event ?? 'ai_employee.setup_request_created',
    source_app: payload.source_app ?? 'OBMC AI Employees',
    received_at: new Date().toISOString(),
    portal_path: payload.portal_path ?? (customer.portal_token ? `/ai-employees/portal/${customer.portal_token}` : null),
    customer,
    request,
    ghl_contact_payload: {
      locationId: payload.ghl_location_id ?? null,
      firstName: customer.contact_name ?? customer.business_name ?? 'AI Employee Lead',
      name: customer.contact_name ?? customer.business_name ?? 'AI Employee Lead',
      email: customer.email ?? null,
      phone: customer.phone ?? null,
      website: customer.website ?? null,
      tags,
      source: 'OBMC AI Employees setup request',
      customFields: [
        { key: 'obmc_ai_plan', field_value: customer.plan_id ?? 'manual' },
        { key: 'obmc_ai_timeline', field_value: request.timeline ?? 'not provided' },
        { key: 'obmc_ai_primary_need', field_value: request.primaryNeed ?? 'not provided' }
      ]
    },
    ghl_opportunity_payload: {
      locationId: payload.ghl_location_id ?? null,
      title: `${customer.business_name ?? customer.contact_name ?? 'New'} - AI Employee Setup`,
      status: 'open',
      source: 'OBMC AI Employees',
      notes: [
        `Plan: ${customer.plan_name ?? customer.plan_id ?? 'manual review'}`,
        `Timeline: ${request.timeline ?? 'not provided'}`,
        `Uses GHL: ${request.currentGhl ?? 'not sure'}`,
        `Primary need: ${request.primaryNeed ?? 'not provided'}`,
        request.notes ? `Notes: ${request.notes}` : null,
        customer.portal_token ? `Portal: /ai-employees/portal/${customer.portal_token}` : null
      ].filter(Boolean).join('\n')
    },
    obmc_task: {
      title: 'Review AI Employee setup request',
      owner: 'OBMC Admin',
      due: 'same business day',
      portal_path: customer.portal_token ? `/ai-employees/portal/${customer.portal_token}` : null,
      summary: `${customer.business_name ?? customer.contact_name ?? 'New request'} wants ${request.primaryNeed ?? 'AI Employee setup'}`
    },
    next_step: 'create_or_update_ghl_contact_then_send_intake_link'
  }
}];
